import subprocess
seqs={}; name=None
for line in open('sequences.fasta'):
    line=line.strip()
    if line.startswith('>'): name=line[1:]; seqs[name]=''
    elif line: seqs[name]+=line.lower()
inp=seqs['input']
comp={'a':'t','t':'a','g':'c','c':'g'}
def rc(s): return ''.join(comp[c] for c in reversed(s))
def tm(s):
    o=subprocess.run(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',s.upper()],capture_output=True,text=True)
    return float(o.stdout.strip())
P=215
# forward anneal downstream, reverse anneal upstream
best=None
fwds=[]; revs=[]
for lf in range(15,37):
    s=inp[P:P+lf]; fwds.append((lf,s,tm(s)))
for lr in range(15,37):
    s=inp[P-lr:P]; revs.append((lr,rc(s),tm(s)))  # tm of primer(revcomp) == tm of template? use primer seq
# recompute rev tm on primer seq
revs=[(lr,rc(inp[P-lr:P]),tm(rc(inp[P-lr:P]))) for lr in range(15,37)]
for lf,fs,ft in fwds:
    if not(58<=ft<=72): continue
    for lr,rs,rt in revs:
        if not(58<=rt<=72): continue
        if abs(ft-rt)<=5:
            best=(lf,ft,fs,lr,rt,rs); 
            print(f'F len{lf} tm{ft:.2f} {fs}')
            print(f'R len{lr} tm{rt:.2f} {rs}')
            print('---'); 
            break
    if best: break
